#!/usr/bin/env python3
"""Benchmark local CPU HF inference against quantized MLX inference."""

from __future__ import annotations

import argparse
import re
import statistics
import subprocess
import sys
import time
from pathlib import Path


SYSTEM_PROMPT = (
    "You are a classifier that determines whether a social media post was "
    "written by a human or generated by AI. Respond with exactly one word: "
    "'ai' or 'human'."
)


def parse_args() -> argparse.Namespace:
    parser = argparse.ArgumentParser(
        description="Benchmark merged CPU inference against quantized MLX inference."
    )
    group = parser.add_mutually_exclusive_group(required=True)
    group.add_argument(
        "--prompt",
        help="Deprecated alias for --instruction. Preserved for compatibility.",
    )
    group.add_argument(
        "--instruction",
        help="Full classification instruction prompt to run through both paths.",
    )
    group.add_argument(
        "--text",
        help="Raw post text to classify. Both backends will build the classifier prompt.",
    )
    parser.add_argument(
        "--hf_model_path",
        default="model_merged",
        help="Path to the merged HF checkpoint used by scripts/infer_mps.py.",
    )
    parser.add_argument(
        "--mlx_model_path",
        default="model_mlx",
        help="Path to the quantized MLX model directory.",
    )
    parser.add_argument(
        "--runs",
        type=int,
        default=1,
        help="Number of runs per backend.",
    )
    parser.add_argument(
        "--max_seq_length",
        type=int,
        default=2048,
        help="Max sequence length for the CPU HF path.",
    )
    return parser.parse_args()


def run_command(cmd: list[str]) -> tuple[float, str, str]:
    start = time.perf_counter()
    completed = subprocess.run(cmd, capture_output=True, text=True, check=True)
    elapsed = time.perf_counter() - start
    return elapsed, completed.stdout, completed.stderr


def parse_cpu_output(stdout: str) -> dict[str, str]:
    data: dict[str, str] = {}
    for line in stdout.splitlines():
        if line.startswith("Prediction: "):
            data["prediction"] = line.split(": ", 1)[1].strip()
        elif line.startswith("P(ai): "):
            data["p_ai"] = line.split(": ", 1)[1].strip()
        elif line.startswith("P(human): "):
            data["p_human"] = line.split(": ", 1)[1].strip()
    return data


def parse_mlx_output(stdout: str) -> dict[str, str]:
    data: dict[str, str] = {}
    lines = [line.rstrip() for line in stdout.splitlines() if line.strip()]
    separator_indices = [i for i, line in enumerate(lines) if line == "=========="]
    if len(separator_indices) >= 2:
        start = separator_indices[0] + 1
        end = separator_indices[1]
        for line in lines[start:end]:
            candidate = line.strip().strip("'\"")
            if candidate:
                data["prediction"] = candidate
                break
    for line in lines:
        if line.startswith("Prompt: "):
            data["prompt_stats"] = line
            match = re.search(r"([0-9.]+) tokens-per-sec", line)
            if match:
                data["prompt_tps"] = match.group(1)
        elif line.startswith("Generation: "):
            data["generation_stats"] = line
            match = re.search(r"([0-9.]+) tokens-per-sec", line)
            if match:
                data["generation_tps"] = match.group(1)
        elif line.startswith("Peak memory: "):
            data["peak_memory"] = line.split(": ", 1)[1].strip()
    return data


def resolve_input_mode_and_value(args: argparse.Namespace) -> tuple[str, str]:
    if args.text is not None:
        return "text", args.text
    if args.instruction is not None:
        return "instruction", args.instruction
    if args.prompt is not None:
        return "instruction", args.prompt
    raise ValueError("One of --text, --instruction, or --prompt is required.")


def build_user_content(raw_input: str, is_instruction: bool) -> str:
    if is_instruction:
        return raw_input
    return (
        "Classify the following social media post as either 'ai' or 'human'.\n\n"
        f"Post: {raw_input}"
    )


def build_cpu_command(
    input_value: str,
    input_mode: str,
    model_path: Path,
    max_seq_length: int,
) -> list[str]:
    cmd = [
        sys.executable,
        "scripts/infer_mps.py",
        "--model_path",
        str(model_path),
        "--device",
        "cpu",
        "--max_seq_length",
        str(max_seq_length),
    ]
    if input_mode == "instruction":
        cmd.extend(["--instruction", input_value])
    elif input_mode == "text":
        cmd.extend(["--text", input_value])
    else:
        raise ValueError(f"Unsupported input mode: {input_mode}")
    return cmd


def build_mlx_command(
    input_value: str,
    input_mode: str,
    model_path: Path,
) -> list[str]:
    user_content = build_user_content(
        input_value,
        is_instruction=input_mode == "instruction",
    )
    return [
        "mlx_lm.generate",
        "--model",
        str(model_path),
        "--system-prompt",
        SYSTEM_PROMPT,
        "--prompt",
        user_content,
        "--max-tokens",
        "1",
        "--temp",
        "0",
    ]


def benchmark_cpu(
    input_value: str,
    input_mode: str,
    model_path: Path,
    runs: int,
    max_seq_length: int,
) -> dict[str, object]:
    timings = []
    parsed: dict[str, str] = {}
    last_stdout = ""
    for _ in range(runs):
        elapsed, stdout, _stderr = run_command(
            build_cpu_command(
                input_value=input_value,
                input_mode=input_mode,
                model_path=model_path,
                max_seq_length=max_seq_length,
            )
        )
        timings.append(elapsed)
        parsed = parse_cpu_output(stdout)
        last_stdout = stdout
    return {
        "backend": "cpu_hf",
        "avg_seconds": statistics.mean(timings),
        "runs": runs,
        "parsed": parsed,
        "raw_stdout": last_stdout,
    }


def benchmark_mlx(
    input_value: str,
    input_mode: str,
    model_path: Path,
    runs: int,
) -> dict[str, object]:
    timings = []
    parsed: dict[str, str] = {}
    last_stdout = ""
    for _ in range(runs):
        elapsed, stdout, _stderr = run_command(
            build_mlx_command(
                input_value=input_value,
                input_mode=input_mode,
                model_path=model_path,
            )
        )
        timings.append(elapsed)
        parsed = parse_mlx_output(stdout)
        last_stdout = stdout
    return {
        "backend": "mlx_quantized",
        "avg_seconds": statistics.mean(timings),
        "runs": runs,
        "parsed": parsed,
        "raw_stdout": last_stdout,
    }


def print_summary(cpu_result: dict[str, object], mlx_result: dict[str, object]) -> None:
    print("Backend comparison")
    print(f"- CPU HF avg seconds: {cpu_result['avg_seconds']:.3f}")
    print(f"- MLX avg seconds: {mlx_result['avg_seconds']:.3f}")

    cpu_parsed = cpu_result["parsed"]
    mlx_parsed = mlx_result["parsed"]
    assert isinstance(cpu_parsed, dict)
    assert isinstance(mlx_parsed, dict)

    print("CPU HF output")
    print(f"- Prediction: {cpu_parsed.get('prediction', 'unknown')}")
    print(f"- P(ai): {cpu_parsed.get('p_ai', 'n/a')}")
    print(f"- P(human): {cpu_parsed.get('p_human', 'n/a')}")

    print("MLX output")
    print(f"- Prediction: {mlx_parsed.get('prediction', 'unknown')}")
    print(f"- Prompt TPS: {mlx_parsed.get('prompt_tps', 'n/a')}")
    print(f"- Generation TPS: {mlx_parsed.get('generation_tps', 'n/a')}")
    print(f"- Peak memory: {mlx_parsed.get('peak_memory', 'n/a')}")


def main() -> None:
    args = parse_args()
    input_mode, input_value = resolve_input_mode_and_value(args)
    hf_model_path = Path(args.hf_model_path).expanduser().resolve()
    mlx_model_path = Path(args.mlx_model_path).expanduser().resolve()

    if not hf_model_path.exists():
        raise FileNotFoundError(f"Missing merged HF model: {hf_model_path}")
    if not mlx_model_path.exists():
        raise FileNotFoundError(f"Missing MLX model: {mlx_model_path}")

    cpu_result = benchmark_cpu(
        input_value=input_value,
        input_mode=input_mode,
        model_path=hf_model_path,
        runs=args.runs,
        max_seq_length=args.max_seq_length,
    )
    mlx_result = benchmark_mlx(
        input_value=input_value,
        input_mode=input_mode,
        model_path=mlx_model_path,
        runs=args.runs,
    )
    print_summary(cpu_result, mlx_result)


if __name__ == "__main__":
    main()
